"""
API Routers for Book Service
"""

from fastapi import APIRouter, HTTPException, Query
from typing import Optional, List
import logging

from services.enrichment import enrichment_service
from database import db
from models.book import BookProfile
from models.author import AuthorProfile

logger = logging.getLogger(__name__)

router = APIRouter(prefix="/api/v3", tags=["books"])


@router.get("/search/book")
async def search_book(
        query: str = Query(..., description="Book title or keywords"),
        force_refresh: bool = False
) -> BookProfile:
    """Search and enrich a book"""
    try:
        # 1. Check database first (unless force refresh)
        if not force_refresh:
            existing = await db.get_book(slugify(query))  # simple check
            if existing:
                logger.info(f"Cache hit for book: {query}")
                return BookProfile.model_validate(existing)

        # 2. Enrich on-demand
        profile = await enrichment_service.enrich_book(query)

        if not profile:
            raise HTTPException(status_code=404, detail="Book not found")

        # 3. Save to MongoDB
        await db.save_book(profile)

        return profile

    except Exception as e:
        logger.error(f"Error enriching book '{query}': {e}")
        raise HTTPException(status_code=500, detail=str(e))


@router.get("/enrich/author")
async def enrich_author(
        name: str = Query(..., description="Author name"),
        force_refresh: bool = False
) -> AuthorProfile:
    """Enrich author profile"""
    try:
        profile = await enrichment_service.enrich_author(name)
        if not profile:
            raise HTTPException(status_code=404, detail="Author not found")

        # TODO: Save author to database (will add later)
        return profile

    except Exception as e:
        logger.error(f"Error enriching author '{name}': {e}")
        raise HTTPException(status_code=500, detail=str(e))


@router.get("/health")
async def health_check():
    return {
        "service": "book-service",
        "status": "healthy",
        "database": "connected"
    }

@router.get("/authors/search")
async def search_authors(
        name: str = Query(..., description="Author name"),
        limit: int = Query(10, description="Max results")
) -> dict:
    """Search for authors"""
    try:
        profile = await enrichment_service.enrich_author(name)
        if profile:
            return {"results": [profile], "total": 1}
        else:
            return {"results": [], "total": 0}
    except Exception as e:
        logger.error(f"Error searching author '{name}': {e}")
        raise HTTPException(status_code=500, detail=str(e))


@router.get("/books/search")
async def search_books(
        q: str = Query(..., description="Book title or keywords"),
        limit: int = Query(10, description="Max results")
) -> dict:
    """Search for books"""
    try:
        profile = await enrichment_service.enrich_book(q)
        if profile:
            return {"results": [profile], "total": 1}
        else:
            return {"results": [], "total": 0}
    except Exception as e:
        logger.error(f"Error searching book '{q}': {e}")
        raise HTTPException(status_code=500, detail=str(e))


@router.get("/series/search")
async def search_series(
        name: str = Query(..., description="Series name"),
        limit: int = Query(10, description="Max results")
) -> dict:
    """Search for series"""
    # TODO: Implement series enrichment
    return {"results": [], "total": 0}


@router.post("/search")
async def unified_search(payload: dict) -> dict:
    """Unified search endpoint"""
    query = payload.get("query")
    search_type = payload.get("type")
    limit = payload.get("limit", 10)

    if not query or not search_type:
        raise HTTPException(status_code=400, detail="Missing query or type")

    try:
        if search_type == "author":
            profile = await enrichment_service.enrich_author(query)
            results = [profile] if profile else []
        elif search_type == "book":
            profile = await enrichment_service.enrich_book(query)
            results = [profile] if profile else []
        elif search_type == "series":
            results = []  # TODO
        else:
            raise HTTPException(status_code=400, detail="Invalid type")

        return {"results": results, "total": len(results)}
    except Exception as e:
        logger.error(f"Error in unified search '{query}' type '{search_type}': {e}")
        raise HTTPException(status_code=500, detail=str(e))
